        _MosaicSize ("Mosaic Size", Float) = 16.0
        _ColorVariation ("Color Variation", Range(0, 1)) = 0.5
    }
    SubShader
    {
        Tags { "RenderType"="Opaque" }
        LOD 200

        Pass
        {
            CGPROGRAM
            #pragma vertex vert
            #pragma fragment frag

            struct appdata
            {
                float4 vertex : POSITION;
                float2 uv : TEXCOORD0;
            };

            struct v2f
            {
                float2 uv : TEXCOORD0;
                float4 vertex : SV_POSITION;
            };

            sampler2D _MainTex;
            float _MosaicSize;
            float _ColorVariation;

            v2f vert (appdata v)
            {
                v2f o;
                o.vertex = UnityObjectToClipPos(v.vertex);
                o.uv = v.uv;
                return o;
            }

            fixed4 frag (v2f i) : SV_Target
            {
                // Calculate the mosaic tile size
                float2 tileSize = float2(_ScreenParams.x / _MosaicSize, _ScreenParams.y / _MosaicSize);

                // Get the tile index based on UV coordinates
                float2 tileIndex = floor(i.uv * tileSize);

                // Sample the texture at the tile index
                fixed4 color = tex2D(_MainTex, tileIndex / tileSize);

                // Add color variation
                color.rgb += tex2D(_MainTex, i.uv).rgb * _ColorVariation;

                return color;
            }
            ENDCG
        }
    }
    FallBack "Diffuse"
}
